class Solution {
public:
    int maxAbsValExpr(vector<int>& arr1, vector<int>& arr2) {
        int n = arr1.size();
        int res = INT_MIN;
        for (int sign1 : {1, -1}) {
            for (int sign2 : {1, -1}) {
                for (int sign3 : {1, -1}) {
                    int maxVal = INT_MIN;
                    for (int i = 0; i < n; i++) {
                        maxVal = max(maxVal, abs(sign1 * arr1[i] + sign2 * arr2[i] + sign3 * i));
                    }
                    res = max(res, maxVal);
                }
                }
            }
        return res;
    }
};
